//! Hard-coded manifest definitions for the 5 standard C headers.
//!
//! Plan 216 takes the recommended approach: manifests are pre-generated by
//! developers rather than requiring libclang/bindgen at build time.

use crate::manifest::*;

/// Return the manifest for a well-known standard header, or `None`.
pub fn get_builtin_manifest(header: &str) -> Option<CHeaderManifest> {
    match header {
        "string.h" | "<string.h>" => Some(string_manifest()),
        "math.h" | "<math.h>" => Some(math_manifest()),
        "stdio.h" | "<stdio.h>" => Some(stdio_manifest()),
        "stdlib.h" | "<stdlib.h>" => Some(stdlib_manifest()),
        "time.h" | "<time.h>" => Some(time_manifest()),
        _ => None,
    }
}

fn p(name: &str, ty: CTypeDesc) -> CParam {
    CParam { name: name.to_string(), ty }
}

fn string_manifest() -> CHeaderManifest {
    CHeaderManifest {
        header: "string.h".into(),
        library: "c".into(),
        functions: vec![
            CFunction {
                name: "strlen".into(),
                params: vec![p("s", CTypeDesc::CStr)],
                return_type: CTypeDesc::Size,
                variadic: false,
            },
            CFunction {
                name: "strcmp".into(),
                params: vec![p("s1", CTypeDesc::CStr), p("s2", CTypeDesc::CStr)],
                return_type: CTypeDesc::Int,
                variadic: false,
            },
            CFunction {
                name: "strncmp".into(),
                params: vec![p("s1", CTypeDesc::CStr), p("s2", CTypeDesc::CStr), p("n", CTypeDesc::Size)],
                return_type: CTypeDesc::Int,
                variadic: false,
            },
            CFunction {
                name: "strcpy".into(),
                params: vec![p("dest", CTypeDesc::PtrMut), p("src", CTypeDesc::CStr)],
                return_type: CTypeDesc::Ptr,
                variadic: false,
            },
            CFunction {
                name: "strcat".into(),
                params: vec![p("dest", CTypeDesc::PtrMut), p("src", CTypeDesc::CStr)],
                return_type: CTypeDesc::Ptr,
                variadic: false,
            },
            CFunction {
                name: "strdup".into(),
                params: vec![p("s", CTypeDesc::CStr)],
                return_type: CTypeDesc::Ptr,
                variadic: false,
            },
            CFunction {
                name: "memset".into(),
                params: vec![p("s", CTypeDesc::PtrMut), p("c", CTypeDesc::Int), p("n", CTypeDesc::Size)],
                return_type: CTypeDesc::Ptr,
                variadic: false,
            },
            CFunction {
                name: "memcpy".into(),
                params: vec![p("dest", CTypeDesc::PtrMut), p("src", CTypeDesc::Ptr), p("n", CTypeDesc::Size)],
                return_type: CTypeDesc::Ptr,
                variadic: false,
            },
        ],
    }
}

