#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_builtin_manifests_exist() {
        assert!(get_builtin_manifest("string.h").is_some());
        assert!(get_builtin_manifest("math.h").is_some());
        assert!(get_builtin_manifest("stdio.h").is_some());
        assert!(get_builtin_manifest("stdlib.h").is_some());
        assert!(get_builtin_manifest("time.h").is_some());
        assert!(get_builtin_manifest("<string.h>").is_some());
        assert!(get_builtin_manifest("nonexistent.h").is_none());
    }

    #[test]
    fn test_string_manifest_serializes() {
        let m = string_manifest();
        let json = serde_json::to_string_pretty(&m).unwrap();
        let back: CHeaderManifest = serde_json::from_str(&json).unwrap();
        assert_eq!(back.header, "string.h");
        assert_eq!(back.functions.len(), 8);
    }

    #[test]
    fn test_math_manifest_functions() {
        let m = math_manifest();
        assert_eq!(m.functions.len(), 10);
        let sqrt = m.functions.iter().find(|f| f.name == "sqrt").unwrap();
        assert_eq!(sqrt.params.len(), 1);
        assert_eq!(sqrt.params[0].ty, CTypeDesc::Double);
        assert_eq!(sqrt.return_type, CTypeDesc::Double);
    }
}
